import{_ as o,c as t,o as e,a4 as a}from"./chunks/framework.HaEZziQ1.js";const u=JSON.parse('{"title":"NodeJS爬虫系统开发","description":"","frontmatter":{},"headers":[],"relativePath":"Document/Node/NodeJS爬虫系统开发.md","filePath":"Document/Node/NodeJS爬虫系统开发.md","lastUpdated":1709668918000}'),l={name:"Document/Node/NodeJS爬虫系统开发.md"},i=a('<h1 id="nodejs爬虫系统开发" tabindex="-1">NodeJS爬虫系统开发 <a class="header-anchor" href="#nodejs爬虫系统开发" aria-label="Permalink to &quot;NodeJS爬虫系统开发&quot;">​</a></h1><p>Nodejs 因为基于JavaScript的语法，对解析html标签有着天然的优势</p><h2 id="爬虫系统以及robots协议介绍" tabindex="-1">爬虫系统以及Robots协议介绍 <a class="header-anchor" href="#爬虫系统以及robots协议介绍" aria-label="Permalink to &quot;爬虫系统以及Robots协议介绍&quot;">​</a></h2><p><strong>爬虫</strong>，是一种自动获取网页内容的程序。是搜索引擎的重要组成部分，因此搜索引擎优化很大程度上就是针对爬虫而做出的优化。</p><p><strong>robots.txt</strong>是一个文本文件，robots.txt是一个协议，不是一个命令。 robots.txt是爬虫要查看的第一个文件。 robots.txt文件告诉爬虫在服务器上什么文件是可以被查看的，搜索机器人就会按照该文件中的内容来确定访问的范围。</p><h2 id="使用环境和技术栈" tabindex="-1">使用环境和技术栈 <a class="header-anchor" href="#使用环境和技术栈" aria-label="Permalink to &quot;使用环境和技术栈&quot;">​</a></h2><p>Express</p><p>Axios</p><p>Cheerio</p><h2 id="实现命令行工具" tabindex="-1">实现命令行工具 <a class="header-anchor" href="#实现命令行工具" aria-label="Permalink to &quot;实现命令行工具&quot;">​</a></h2><p>什么是命令行工具：</p><ul><li>客户端软件</li><li>用户交互</li><li>面向开发者</li><li>...</li></ul><p>开发命令行工具步骤：</p><ul><li>process.argv 与解析 process.argv</li><li>npm install commander</li><li>npm install optimist</li><li>npm install prompt</li><li>输出帮助信息</li><li>输出彩色文本</li></ul><p>运行脚本到命令执行总共需要几步：</p><ul><li>脚本与运行脚本</li><li>设置默认的运行时</li><li>使用chmod分配执行权限</li><li>设置环境变量</li><li>开始使用命令行</li></ul>',16),r=[i];function s(n,d,p,c,_,h){return e(),t("div",null,r)}const b=o(l,[["render",s]]);export{u as __pageData,b as default};
